// TOPIC_CHANNELS 파싱: 채널별 (channelId, topic) 쌍 목록으로 펼치기
// 형식: "채널이름/채널ID+채널이름/채널ID+..."
// 예: "노마드코더/UCUpJs89fSBXNolQGOYKn0YQ+조코딩/UCQNE2JmbasNYbjGAcuBiRRg"
const raw = $env.TOPIC_CHANNELS || '';
if (!raw.trim()) return [{ json: { skip: true, reason: 'TOPIC_CHANNELS 미설정' } }];

const channels = [];
for (const ch of raw.split('+')) {
  const slashIdx = ch.indexOf('/');
  if (slashIdx < 0) continue;
  const channelName = ch.slice(0, slashIdx).trim();
  const channelId   = ch.slice(slashIdx + 1).trim();
  if (channelName && channelId) channels.push({ channelId, topic: channelName });
}

if (channels.length === 0) return [{ json: { skip: true, reason: '파싱된 채널 없음' } }];
return channels.map(ch => ({ json: ch }));

// YouTube RSS 조회 (최대 10회 재시도, 3초 간격) + 새 영상 필터링 (Shorts 제외)
const channelId = $json.channelId || '';
const topic = $json.topic || '';
const RSS_URL = `https://www.youtube.com/feeds/videos.xml?channel_id=${channelId}`;
const MAX_RETRIES = 10;
const WAIT_MS = 3000;

let xml = '';
for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
  try {
    const body = await $helpers.httpRequest({
      method: 'GET',
      url: RSS_URL,
    });
    if (typeof body === 'string' && body.includes('<feed')) {
      xml = body;
      break;
    }
    // 응답은 왔지만 유효한 XML이 아님 (404 HTML 등)
    if (attempt < MAX_RETRIES) {
      await new Promise(r => setTimeout(r, WAIT_MS));
    }
  } catch (e) {
    // HTTP 에러 (404, 500 등)
    if (attempt < MAX_RETRIES) {
      await new Promise(r => setTimeout(r, WAIT_MS));
    }
  }
}

if (!xml) {
  return [{ json: { skip: true, channelId, topic, reason: `RSS 조회 실패 (${MAX_RETRIES}회 재시도)` } }];
}

// RSS 파싱: Shorts 제외, 1.5시간 이내
const entries = [];
const entryRegex = /<entry>([\s\S]*?)<\/entry>/g;
let match;

while ((match = entryRegex.exec(xml)) !== null) {
  const block = match[1];
  const videoId = (block.match(/<yt:videoId>([^<]+)<\/yt:videoId>/) || [])[1];
  const title = (block.match(/<title>([^<]+)<\/title>/) || [])[1] || '';
  const published = (block.match(/<published>([^<]+)<\/published>/) || [])[1] || '';
  const linkMatch = block.match(/<link rel="alternate" href="([^"]+)"/);
  const videoLink = linkMatch ? linkMatch[1] : '';

  if (!videoId) continue;

  // YouTube Shorts 제외 (NotebookLM이 Shorts 트랜스크립트를 지원하지 않음)
  if (videoLink.includes('/shorts/')) continue;

  const publishedMs = new Date(published).getTime();
  const cutoffMs = Date.now() - 90 * 60 * 1000; // 1.5시간 이내

  if (publishedMs >= cutoffMs) {
    entries.push({
      videoUrl: `https://www.youtube.com/watch?v=${videoId}`,
      title: title.replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>'),
      publishedAt: published,
      channelId,
      topic,
    });
  }
}

if (entries.length === 0) {
  return [{ json: { skip: true, channelId, topic, reason: '새 영상 없음 (Shorts 포함 필터링)' } }];
}

return entries.map(e => ({ json: e }));

// 결과 로깅
const result = $input.item.json;

if (result.duplicate) {
  console.log(`[WF-09] 중복 건너뜀`);
} else if (result.added) {
  console.log(`[WF-09] 소스 추가 완료 (cleaned=${result.cleaned_up})`);
} else if (result.error) {
  console.error(`[WF-09] 소스 추가 실패: ${result.error}`);
}

return [{ json: result }];
